class BiometricAuth {
  static final LocalAuthentication auth = LocalAuthentication();
  static final String _authKey = 'isAuthenticated';

  static Future<bool> authenticate() async {
    try {
      final bool canAuthenticate = await auth.canCheckBiometrics;
      final List<BiometricType> availableBiometrics = await auth.getAvailableBiometrics();
      
      if (canAuthenticate && availableBiometrics.isNotEmpty) {
        final bool authenticated = await auth.authenticate(
          localizedReason: 'Please authenticate to access the app',
          options: const AuthenticationOptions(
            stickyAuth: true,
            biometricOnly: true,
          ),
        );
        
        if (authenticated) {
          _setAuthenticatedStatus(true);
          return true;
        }
      }
    } catch (e) {
      print('Biometric authentication failed: $e');
    }
    
    return false;
  }

  static Future<bool> checkAuthenticationStatus() async {
    final SharedPreferences prefs = await SharedPreferences.getInstance();
    return prefs.getBool(_authKey) ?? false;
  }

  static Future<void> _setAuthenticatedStatus(bool status) async {
    final SharedPreferences prefs = await SharedPreferences.getInstance();
    await prefs.setBool(_authKey, status);
  }

  static Future<void> clearAuthenticationStatus() async {
    final SharedPreferences prefs = await SharedPreferences.getInstance();
    await prefs.remove(_authKey);
  }
}

